changeSet.sql:
CREATE TABLE industry ( id BIGSERIAL PRIMARY KEY, code VARCHAR(50) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, description TEXT, parent_id BIGINT, active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT fk_industry_parent FOREIGN KEY (parent_id) REFERENCES industry(id) ON DELETE SET NULL );
CREATE INDEX idx_industry_parent ON industry(parent_id); CREATE INDEX idx_industry_active ON industry(active); CREATE INDEX idx_industry_name ON industry(name);
INSERT INTO industry (code, name) VALUES ('AGR', 'الزراعة'), ('IND', 'الصناعة'), ('CON', 'التشييد والبناء'), ('TRD', 'التجارة'), ('TRN', 'النقل والخدمات اللوجستية'), ('ITC', 'تقنية المعلومات والاتصالات'), ('FIN', 'الخدمات المالية'), ('HLT', 'الرعاية الصحية'), ('EDU', 'التعليم'), ('ENG', 'الطاقة والمرافق'), ('HOS', 'السياحة والضيافة'), ('MED', 'الإعلام والترفيه'), ('RLE', 'العقارات'), ('GOV', 'القطاع الحكومي'), ('NPO', 'المنظمات غير الربحية');
INSERT INTO industry (code, name, parent_id) VALUES ('AGR-CROP', 'الزراعة النباتية', (SELECT id FROM industry WHERE code='AGR')), ('AGR-LIVE', 'الثروة الحيوانية', (SELECT id FROM industry WHERE code='AGR'));
